// ===========================================================================
// Standalone landing page â€” rendered without a FileView
// ===========================================================================

function renderStandaloneLandingPage(containerEl, plugin) {
  containerEl.empty();
  const wrapper = containerEl.createEl("div", { cls: "docx-landing" });

  const style = wrapper.createEl("style");
  style.textContent =
    ".docx-landing { padding: 24px 32px; font-family: var(--font-interface); color: var(--text-normal); max-width: 900px; margin: 0 auto; }" +
    ".docx-landing h2 { font-size: 16px; font-weight: 600; margin: 0 0 12px; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.5px; }" +
    ".docx-landing h3 { font-size: 13px; font-weight: 600; margin: 0 0 8px; color: var(--text-muted); }" +
    ".docx-landing .template-grid { display: flex; flex-wrap: wrap; gap: 12px; margin-bottom: 24px; }" +
    ".docx-landing .template-card { width: 120px; padding: 16px 12px; border: 1px solid var(--background-modifier-border); border-radius: 8px; cursor: pointer; text-align: center; transition: border-color 0.15s, background 0.15s; }" +
    ".docx-landing .template-card:hover { border-color: var(--interactive-accent); background: var(--background-modifier-hover); }" +
    ".docx-landing .template-card .icon { font-size: 32px; margin-bottom: 8px; }" +
    ".docx-landing .template-card .label { font-size: 12px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }" +
    ".docx-landing .recent-table { width: 100%; border-collapse: collapse; }" +
    ".docx-landing .recent-table th { text-align: left; padding: 6px 12px; border-bottom: 2px solid var(--background-modifier-border); font-size: 12px; color: var(--text-muted); font-weight: 600; }" +
    ".docx-landing .recent-table td { padding: 8px 12px; border-bottom: 1px solid var(--background-modifier-border); font-size: 13px; cursor: pointer; }" +
    ".docx-landing .recent-table tr:hover td { background: var(--background-modifier-hover); }" +
    ".docx-landing .recent-table .date { color: var(--text-muted); white-space: nowrap; width: 140px; }" +
    ".docx-landing .recent-table .ext { color: var(--text-muted); white-space: nowrap; width: 60px; font-family: var(--font-monospace); font-size: 11px; }";

  const app = plugin.app;
  const docxDir = plugin.settings.templateDir || "_docx-templates";
  const pptxDir = plugin.settings.pptxTemplateDir || "_pptx-templates";

  // Phase 8 — Per-format template renderer. Picks templates from `dir`,
  // sorts blanks first, renders a grid, wires each card to FileNameModal
  // with the right extension + blank-base64 fallback.
  function renderTemplateSection(headingText, dir, ext, blankBase64, blankName) {
    wrapper.createEl("h3", { text: headingText });
    const grid = wrapper.createEl("div", { cls: "template-grid" });
    const templates = [];
    for (const f of app.vault.getFiles()) {
      if (f.path.startsWith(dir + "/") && f.extension === ext) {
        templates.push({ name: f.basename, path: f.path });
      }
    }
    templates.sort((a, b) => {
      if (a.name === blankName) return -1;
      if (b.name === blankName) return 1;
      return a.name.localeCompare(b.name);
    });
    if (templates.length === 0) templates.push({ name: blankName, path: "" });

    const dotExt = "." + ext;
    const blankIcon = ext === "pptx" ? "\u{1F4FD}️" : "\u{1F4C4}";  // film projector / page
    const tmplIcon  = ext === "pptx" ? "\u{1F39E}️" : "\u{1F4DD}";  // film frames / pencil

    for (const tmpl of templates) {
      const card = grid.createEl("div", { cls: "template-card" });
      card.createEl("div", { cls: "icon", text: tmpl.name === blankName ? blankIcon : tmplIcon });
      card.createEl("div", { cls: "label", text: tmpl.name });
      card.addEventListener("click", () => {
        const modal = new FileNameModal(app, tmpl.name, async (filename) => {
          if (!filename) return;
          if (!filename.endsWith(dotExt)) filename += dotExt;
          if (await app.vault.adapter.exists(filename)) {
            new obsidian.Notice('File "' + filename + '" already exists.');
            return;
          }
          if (tmpl.path && await app.vault.adapter.exists(tmpl.path)) {
            await app.vault.adapter.copy(tmpl.path, filename);
          } else {
            const bytes = Uint8Array.from(atob(blankBase64), (c) => c.charCodeAt(0));
            await app.vault.adapter.writeBinary(filename, bytes);
          }
          new obsidian.Notice("Created: " + filename);
          const f = app.vault.getAbstractFileByPath(filename);
          if (f && f instanceof obsidian.TFile) {
            const leaf = app.workspace.getLeaf(true);
            await leaf.openFile(f);  // Obsidian routes by registered extension
          }
        }, dotExt);
        modal.open();
      });
    }
  }

  // --- NEW section ---
  wrapper.createEl("h2", { text: "New" });
  renderTemplateSection("Document", docxDir, "docx", BLANK_DOCX_BASE64, "Blank Document");
  renderTemplateSection("Presentation", pptxDir, "pptx", BLANK_PPTX_BASE64, "Blank Presentation");

  // --- RECENT section (merged, sorted by mtime) ---
  wrapper.createEl("h2", { text: "Recent" });
  const recentFiles = app.vault.getFiles()
    .filter((f) => (f.extension === "docx" || f.extension === "pptx") &&
                   !f.path.startsWith(docxDir + "/") &&
                   !f.path.startsWith(pptxDir + "/"))
    .sort((a, b) => b.stat.mtime - a.stat.mtime)
    .slice(0, 20);

  if (recentFiles.length === 0) {
    wrapper.createEl("p", { text: "No recent .docx or .pptx files found." });
  } else {
    const table = wrapper.createEl("table", { cls: "recent-table" });
    const thead = table.createEl("thead");
    const headerRow = thead.createEl("tr");
    headerRow.createEl("th", { text: "File" });
    headerRow.createEl("th", { text: "Type", cls: "ext" });
    headerRow.createEl("th", { text: "Modified", cls: "date" });
    const tbody = table.createEl("tbody");
    for (const f of recentFiles) {
      const row = tbody.createEl("tr");
      row.createEl("td", { text: f.basename });
      row.createEl("td", { text: "." + f.extension, cls: "ext" });
      const date = new Date(f.stat.mtime);
      row.createEl("td", {
        text: date.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" }),
        cls: "date",
      });
      row.addEventListener("click", async () => {
        const leaf = app.workspace.getLeaf(true);
        await leaf.openFile(f);  // Obsidian routes by registered extension
      });
    }
  }
}

// ===========================================================================
// Plugin
// ===========================================================================

class OnlyObsidianTestPlugin extends obsidian.Plugin {
  async onload() {
    await this.loadSettings();
    DEBUG = !!this.settings.debugLogging;
    // Set up file-based logging BEFORE the first dlog so onload start is captured.
    await initDebugLog(this);
    // Phase 13 reverse migration. Rewrites legacy workspace state +
    // settings.assetZipSource filename to the obsidi-office form.
    // Idempotent â€” self-no-ops after first onload post-rename.
    await this._migrateLegacyState();
    dlog("onload");

    const adapter = this.app.vault.adapter;
    const pluginDirRel = this.manifest.dir;
    this.pluginDirRel = pluginDirRel;  // for vio access from method scope (zip install, etc.)
    // Vault-relative paths (work on both platforms via vio.*).
    this.onlyOfficeRel = vio.join(pluginDirRel, "assets/onlyoffice");
    this.x2tRel        = vio.join(pluginDirRel, "assets/x2t");
    this.x2tFontsRel   = vio.join(pluginDirRel, "assets/x2t-fonts");
    this.shimRel       = vio.join(pluginDirRel, "assets/docx-viewer/transport-shim.js");
    this.mockSocketRel = vio.join(pluginDirRel, "assets/docx-viewer/mock-socket.js");

    // Absolute paths (desktop only â€” used by code paths that still need fs:
    //   - Emscripten's locateFile callback (X2tConverter desktop branch)
    //   - The legacy AssetPatcher (runtime HTML rewriting on disk)
    //   - The legacy _downloadAssets (https/tar.gz fallback)
    // On mobile these stay null; consumer code is gated on isMobile.
    let basePath = null;
    let pluginAbs = null;
    if (!isMobile && adapter.getBasePath) {
      basePath = adapter.getBasePath();
    }
    if (basePath) {
      pluginAbs = path.join(basePath, pluginDirRel);
      this.pluginAbs     = pluginAbs;  // for lazy loaders (pdf-lib, etc.)
      this.onlyOfficeDir = path.join(pluginAbs, "assets", "onlyoffice");
      this.x2tDir        = path.join(pluginAbs, "assets", "x2t");
      this.shimAbs       = path.join(pluginAbs, "assets", "docx-viewer", "transport-shim.js");
      this.mockSocketAbs = path.join(pluginAbs, "assets", "docx-viewer", "mock-socket.js");
    } else {
      this.pluginAbs     = null;
      this.onlyOfficeDir = null;
      this.x2tDir        = null;
      this.shimAbs       = null;
      this.mockSocketAbs = null;
    }

    // System fonts dir for x2t metric reads. Desktop only â€” iPad sandboxes
    // its system fonts so x2t relies on the shipped font subset (Phase 8).
    if (!isMobile && typeof process !== "undefined" && process.platform) {
      if (process.platform === "win32")       this.fontsDir = "C:\\Windows\\Fonts";
      else if (process.platform === "darwin") this.fontsDir = "/Library/Fonts";
      else                                    this.fontsDir = "/usr/share/fonts";
      dlog("x2t fontsDir (system fonts):", this.fontsDir);
    } else {
      this.fontsDir = null;
    }

    // Asset base URL â€” vault-relative input â†’ app:// (desktop) or
    // capacitor:// (mobile) URL via adapter.getResourcePath. Works on both
    // platforms; the earlier basePath+path.relative form was desktop-only.
    this.assetBaseUrl = adapter.getResourcePath(this.onlyOfficeRel).replace(/\?.*$/, "");
    dlog("assetBaseUrl:", this.assetBaseUrl);

    // Register Settings tab BEFORE the asset check. If assets are missing
    // and no assetZipSource is configured, onload bails with a notice â€”
    // the Settings tab needs to be available so the user can configure
    // the zip source and trigger install. Otherwise it's chicken-and-egg.
    this.addSettingTab(new SettingsTab(this.app, this));

    // Check assets â€” vio-based existence checks (mobile-safe). Same four
    // canaries as the previous fs-based version (onlyoffice tree + x2t
    // binaries) so existing desktop installs without the Phase-8 font
    // subset or the spellcheck dictionaries don't trigger a reinstall.
    const assetsNeeded = !(await vio.exists(this, this.onlyOfficeRel)) ||
      !(await vio.exists(this, this.x2tRel)) ||
      !(await vio.exists(this, vio.join(this.x2tRel, "x2t.js"))) ||
      !(await vio.exists(this, vio.join(this.x2tRel, "x2t.wasm"))) ||
      !(await vio.exists(this, vio.join(this.onlyOfficeRel, "sdkjs/slide/sdk-all.js")));

    if (assetsNeeded) {
      dlog("assets missing â€” starting install");
      // Phase B3 â€” prefer the zip-based flow when assetZipSource is set.
      // Falls back to the legacy streaming-https/tar.gz flow on desktop when
      // the setting is empty, so existing dev workflows keep working until
      // zip-flow proves universal.
      const zipSrc = (this.settings.assetZipSource || "").trim();
      if (zipSrc) {
        // Phase B4.3 â€” background install. Don't await â€” extracting ~1000
        // files takes long enough that Obsidian fires its "plugin taking
        // too long" warning if onload blocks. Detach the install, show a
        // clear notice, and bail. User reloads when "Assets installed"
        // appears. Subsequent loads find assets present and skip this.
        new obsidian.Notice(
          "Obsidi-Office: Installing assets in background. " +
          "Reload Obsidian when the 'Assets installed' notice appears.",
          0
        );
        this._downloadAssetsViaZip(zipSrc).then((ok) => {
          if (!ok) {
            new obsidian.Notice("Obsidi-Office: asset install failed. See console.", 15000);
          }
        });
        return;
      }
      if (!isMobile && pluginAbs) {
        // Legacy https/tar fallback â€” synchronous, desktop only. Kept for
        // users who haven't set assetZipSource yet.
        const ok = await this._downloadAssets(pluginAbs);
        if (!ok) {
          new obsidian.Notice("Obsidi-Office: asset download failed. See console for details.", 15000);
          return;
        }
      } else {
        new obsidian.Notice(
          "Obsidi-Office: assets missing and no Asset zip source configured. " +
          "Set one in plugin settings (vault-relative path or http(s) URL).",
          15000
        );
        return;
      }
    }

    // Phase 4 â€” write the two slide-engine stub files that the OnlyOffice
    // DocumentServer would generate at startup but aren't in the static zip.
    // Idempotent; safe to run every load. Mobile-safe (uses vio).
    await this._ensureThemesStubs();

    // Patch the tree (idempotent) â€” DESKTOP ONLY.
    // Runtime AssetPatcher uses fs.readFileSync/writeFileSync to inject the
    // transport-shim <script> tag and replace socket.io.min.js. Mobile gets
    // these substitutions baked into the zip at build time (Phase 3 build-
    // assets.js prepatch), so this step is unnecessary and would crash on
    // missing fs.
    if (!isMobile && this.onlyOfficeDir && this.shimAbs && this.mockSocketAbs &&
        fs.existsSync(this.onlyOfficeDir) && fs.existsSync(this.shimAbs) && fs.existsSync(this.mockSocketAbs)) {
      const r = this.runPatcher();
      if (r.errors.length) elog("patcher errors:", r.errors);
    }

    // x2t + bridge. The converter accepts both relative + absolute paths
    // so it can route via vio (vault adapter, mobile-safe) for the assets
    // shipped inside the plugin and via vioAbs (fs sync) for system fonts.
    this.converter = new X2tConverter(this, {
      x2tRel:   this.x2tRel,
      x2tAbs:   this.x2tDir,
      // Shipped metric-only font subset (~5.6 MB, 44 .ttf files produced by
      // scripts/subset-fonts.py). Byte-identical x2t output vs full system
      // fonts. On desktop this loads additively with fontsAbs (system dir);
      // on mobile this is the only source x2t sees (OS sandboxes system fonts).
      // If the directory doesn't exist (e.g. older installs that only ran the
      // legacy streaming-https tar.gz), X2tConverter._loadFonts silently
      // skips it and falls through to fontsAbs.
      fontsRel: this.x2tFontsRel,
      fontsAbs: this.fontsDir,   // C:\Windows\Fonts on desktop
    });
    this.bridge = new TransportBridge({
      plugin:    this,
      converter: this.converter,
      fontsRel:  vio.join(this.onlyOfficeRel, "fonts"),
      fontsDir:  this.onlyOfficeDir ? path.join(this.onlyOfficeDir, "fonts") : null,
      // Spellcheck asset roots (vault-relative). getSpellAsset reads are
      // strictly constrained to these prefixes â€” anything outside is rejected.
      spellAssetRoots: [
        vio.join(this.onlyOfficeRel, "sdkjs/common/spell/spell"),
        vio.join(pluginDirRel, "assets/dictionaries"),
      ],
      onSave: async (filePath, docxBytes) => {
        const f = this.app.vault.getAbstractFileByPath(filePath);
        if (f && f instanceof obsidian.TFile) {
          await this.app.vault.modifyBinary(f, docxBytes);
        } else {
          await adapter.writeBinary(filePath, docxBytes);
        }
      }
    });
    this.bridge.attach(window);

    this.registerView(VIEW_TYPE, (leaf) => new DocxView(leaf, this));
    this.registerView(VIEW_TYPE_PPTX, (leaf) => new PptxView(leaf, this));
    // After fork consolidation there is only one docx plugin.
    try { this.registerExtensions(["docx"], VIEW_TYPE); } catch (e) {
      elog("registerExtensions failed:", e.message);
    }
    try { this.registerExtensions(["pptx"], VIEW_TYPE_PPTX); } catch (e) {
      elog("registerExtensions for pptx failed:", e.message);
    }

    // (Settings tab registered earlier â€” see comment near assetBaseUrl.)

    this.addCommand({
      id: "onlyobsidian-open-current",
      name: "Open current .docx/.pptx in Obsidi-Office",
      checkCallback: (checking) => {
        const f = this.app.workspace.getActiveFile();
        if (!f || !/\.(docx|pptx)$/i.test(f.path)) return false;
        if (!checking) this._openInView(f);
        return true;
      }
    });

    // Ribbon icon â€” opens landing page.
    // Can't use setViewState because FileView requires a file.
    // Instead, render the landing page directly using a standalone function.
    const plugin = this;
    this.addRibbonIcon("file-text", "Obsidi-Office", () => {
      const leaf = this.app.workspace.getLeaf(true);
      this.app.workspace.setActiveLeaf(leaf, { focus: true });
      renderStandaloneLandingPage(leaf.view.containerEl, plugin);
    });

    // Template directory setup
    await this._initTemplateDir();
    this._injectTemplateDirCSS();

    // Sidecar metadata: hide *.docx.md from file explorer
    this._injectSidecarCSS();

    // Sidecar metadata: auto-rename/delete sidecars when .docx/.pptx files
    // change. Path concat (`file.path + ".md"`) works for both extensions —
    // the sidecar is just `<original-filename>.md`, regardless of source.
    const isSidecarParent = (f) => f instanceof obsidian.TFile &&
      (f.extension === "docx" || f.extension === "pptx");
    this.registerEvent(this.app.vault.on("rename", (file, oldPath) => {
      if (isSidecarParent(file)) {
        const oldSidecar = oldPath + ".md";
        const newSidecar = file.path + ".md";
        const sf = this.app.vault.getAbstractFileByPath(oldSidecar);
        if (sf && sf instanceof obsidian.TFile) {
          this.app.vault.rename(sf, newSidecar);
          dlog("sidecar renamed:", oldSidecar, "->", newSidecar);
        }
      }
    }));
    this.registerEvent(this.app.vault.on("delete", (file) => {
      if (isSidecarParent(file)) {
        const sidecarPath = file.path + ".md";
        const sf = this.app.vault.getAbstractFileByPath(sidecarPath);
        if (sf && sf instanceof obsidian.TFile) {
          this.app.vault.delete(sf);
          dlog("sidecar deleted:", sidecarPath);
        }
      }
    }));

    // Listen for metadata button postMessage from editor iframe
    this._metadataHandler = (ev) => {
      if (!ev.data || !ev.data.type) return;
      if (ev.data.type === "obsidi-office-metadata") {
        const filePath = ev.data.filePath;
        if (filePath) {
          const modal = new MetadataModal(this.app, filePath);
          modal.open();
        }
      }
      // Accept both the post-Phase-13 message type and the pre-Phase-13
      // "obsidi-office-mobile-*" variant. iPad's mock-socket.js comes from
      // the asset zip, which was built from the mobile fork BEFORE the
      // Phase 13 rebrand â€” so existing installs are still emitting the
      // -mobile-suffixed names. A zip rebuild + reinstall would fix this
      // properly; this branch is a compatibility bridge for installs that
      // haven't been reinstalled yet.
      if ((ev.data.type === "obsidi-office-print" || ev.data.type === "obsidi-office-mobile-print") && ev.data.images) {
        this._printDocument(ev.data.images, ev.data.pageMmW, ev.data.pageMmH);
        // Iframe overlay can hide as soon as the print iframe takes over.
        this._notifyPdfDone(null);
      }
      if ((ev.data.type === "obsidi-office-pdf-export" || ev.data.type === "obsidi-office-mobile-pdf-export") && ev.data.pages) {
        dlog("pdf-export received (type=" + ev.data.type + "), pages:", ev.data.pages.length, "basename:", ev.data.basename, "transient:", !!ev.data.transientPrint);
        this._exportPdfToVault(ev.data).then(() => {
          dlog("_exportPdfToVault resolved");
        }).catch((err) => {
          elog("PDF export failed:", err && err.stack || err);
          new obsidian.Notice("PDF export failed: " + (err.message || err));
          this._notifyPdfDone(null);
        });
      }
      // (obsidi-office-pdf-diagnostic handler removed 2026-04-29 â€” diagnostic
      //  probes were development-only; PDF export now ships via the print-
      //  preview API. Lessons preserved in vault decisions/2026-04.md and
      //  meta/lessons.md under 2026-04-29.)
    };
    window.addEventListener("message", this._metadataHandler);

    new obsidian.Notice("Obsidi-Office loaded.");
  }

  async onunload() {
    if (this._metadataHandler) window.removeEventListener("message", this._metadataHandler);
    dlog("onunload");
    if (this.bridge) this.bridge.detach(window);
    this.app.workspace.detachLeavesOfType(VIEW_TYPE);
    this.app.workspace.detachLeavesOfType(VIEW_TYPE_PPTX);
  }

  async loadSettings() {
    this.settings = Object.assign({}, DEFAULT_SETTINGS, await this.loadData());
  }

  // Phase 13 reverse migration helper. Two jobs, both idempotent:
  //
  //   1. Workspace state: any leaf currently using a pre-rename docx
  //      view-type ("onlyobsidian-test-docx" or "onlyobsidian-mobile-docx")
  //      is rewritten via setViewState to the new view-type, preserving
  //      the file path. Existing .docx tabs survive the rename without
  //      manual close/reopen.
  //   2. Settings: if settings.assetZipSource still references the
  //      pre-decision-#4 zip filename ("obsidi-office-mobile-assets-
  //      v9.3.1.zip"), rewrite it to the dropped-suffix form
  //      ("obsidi-office-assets-v9.3.1.zip") so the Phase B3 install
  //      flow doesn't fail with "zip not found" on the renamed asset.
  //
  // Called early in onload (after loadSettings + initDebugLog) so the
  // migration finishes before any DocxView leaf factory runs.
  async _migrateLegacyState() {
    const OLD_VIEW_TYPES = ["onlyobsidian-test-docx", "onlyobsidian-mobile-docx"];
    const migrations = [];
    try {
      this.app.workspace.iterateAllLeaves((leaf) => {
        try {
          const state = leaf.getViewState && leaf.getViewState();
          if (state && OLD_VIEW_TYPES.indexOf(state.type) !== -1 &&
              state.state && state.state.file) {
            migrations.push({ leaf, file: state.state.file });
          }
        } catch (e) { /* ignore individual-leaf failures */ }
      });
    } catch (e) { /* ignore iterate failures */ }
    for (const { leaf, file } of migrations) {
      try {
        await leaf.setViewState({ type: VIEW_TYPE, state: { file } });
        dlog("migrated leaf view-type to", VIEW_TYPE, "for", file);
      } catch (e) {
        elog("leaf view-type migration failed:", e && e.message ? e.message : e);
      }
    }

    const zip = this.settings && this.settings.assetZipSource;
    if (typeof zip === "string" && /obsidi-office-mobile-assets-v9\.3\.1\.zip$/.test(zip)) {
      this.settings.assetZipSource =
        zip.replace(/obsidi-office-mobile-assets-v9\.3\.1\.zip$/, "obsidi-office-assets-v9.3.1.zip");
      try {
        await this.saveSettings();
        dlog("migrated settings.assetZipSource: dropped 'mobile' qualifier");
      } catch (e) {
        elog("assetZipSource migration save failed:", e && e.message ? e.message : e);
      }
    }
  }

  async saveSettings() {
    await this.saveData(this.settings);
    DEBUG = !!this.settings.debugLogging;
  }

  runPatcher() {
    const patcher = new AssetPatcher(this.onlyOfficeDir, this.shimAbs, this.mockSocketAbs);
    const r = patcher.run();
    dlog("patcher result:", r);
    return r;
  }

  async _downloadAssets(pluginAbs) {
    const ASSET_URL = "https://github.com/GrandPa-source/Obsidi-Office/releases/download/v0.1.0-assets/onlyobsidian-assets-v9.3.1-full-fonts.tar.gz";
    const assetsDir = path.join(pluginAbs, "assets");
    const notice = new obsidian.Notice("Obsidi-Office: Downloading OnlyOffice assets (207 MB)...", 0);

    try {
      // Download the archive via Node.js https (streams to disk, shows progress).
      // Obsidian's requestUrl() loads the entire file into RAM which is too slow for 207 MB.
      dlog("downloading assets from:", ASSET_URL);
      const tarGzPath = path.join(pluginAbs, "_assets-download.tar.gz");

      await new Promise((resolve, reject) => {
        const https = require("https");
        const follow = (url, redirects) => {
          if (redirects > 5) { reject(new Error("Too many redirects")); return; }
          https.get(url, (res) => {
            if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
              follow(res.headers.location, redirects + 1);
              return;
            }
            if (res.statusCode !== 200) {
              reject(new Error("HTTP " + res.statusCode));
              return;
            }
            const totalBytes = parseInt(res.headers["content-length"] || "0", 10);
            let downloaded = 0;
            const file = fs.createWriteStream(tarGzPath);
            res.on("data", (chunk) => {
              downloaded += chunk.length;
              file.write(chunk);
              if (totalBytes > 0) {
                const pct = Math.round((downloaded / totalBytes) * 100);
                const mb = (downloaded / 1048576).toFixed(0);
                notice.setMessage("Obsidi-Office: Downloading assets... " + mb + " MB / " +
                  (totalBytes / 1048576).toFixed(0) + " MB (" + pct + "%)");
              }
            });
            res.on("end", () => { file.end(); file.on("finish", resolve); });
            res.on("error", reject);
          }).on("error", reject);
        };
        follow(ASSET_URL, 0);
      });
      dlog("downloaded to:", tarGzPath, "size:", fs.statSync(tarGzPath).size);
      notice.setMessage("Obsidi-Office: Download complete. Extracting...");

      // Extract using tar (available in Git Bash on Windows, native on Mac/Linux)
      const { execSync } = require("child_process");
      execSync('tar -xzf "' + tarGzPath + '" -C "' + assetsDir + '"', {
        timeout: 120000,
        windowsHide: true,
      });
      dlog("extraction complete");

      // Clean up temp file
      try { fs.unlinkSync(tarGzPath); } catch (e) {}

      // Verify extraction
      const x2tOk = fs.existsSync(path.join(assetsDir, "x2t", "x2t.js"));
      const ooOk = fs.existsSync(path.join(assetsDir, "onlyoffice", "web-apps"));
      if (!x2tOk || !ooOk) {
        elog("extraction verification failed â€” x2t:", x2tOk, "onlyoffice:", ooOk);
        notice.setMessage("Obsidi-Office: Extraction failed. Check console.");
        setTimeout(() => notice.hide(), 8000);
        return false;
      }

      notice.setMessage("Obsidi-Office: Assets installed. Reload to activate.");
      setTimeout(() => notice.hide(), 5000);
      dlog("assets installed successfully");
      return true;
    } catch (err) {
      elog("asset download/extract failed:", err);
      notice.setMessage("Obsidi-Office: Download failed â€” " + (err.message || err));
      setTimeout(() => notice.hide(), 10000);
      return false;
    }
  }

  // Phase B3 â€” runtime asset delivery via pre-packaged zip. `source` is
  // either an http(s) URL (production / iPad) or a vault-relative path to
  // a local zip (dev). Returns true on success.
  async _downloadAssetsViaZip(source) {
    const notice = new obsidian.Notice("Obsidi-Office: Preparing assets...", 0);
    try {
      // 1. Fetch zip bytes
      let zipBytes;
      if (/^https?:\/\//i.test(source)) {
        notice.setMessage("Obsidi-Office: Downloading assets...");
        const r = await obsidian.requestUrl({ url: source });
        zipBytes = new Uint8Array(r.arrayBuffer);
      } else {
        notice.setMessage("Obsidi-Office: Reading local asset zip...");
        const buf = await vio.readBinary(this, source);
        zipBytes = new Uint8Array(buf);
      }
      dlog("zip bytes:", zipBytes.length);

      // 2. Extract via fflate (vendored at lib/fflate.umd.js; see loadFflate)
      notice.setMessage("Obsidi-Office: Extracting " +
        (zipBytes.length / 1048576).toFixed(0) + " MB...");
      const fflate = await loadFflate(this);
      const entries = fflate.unzipSync(zipBytes);
      const fileNames = Object.keys(entries).filter(n => !n.endsWith("/") && entries[n].length > 0);
      dlog("zip entries:", fileNames.length, "files");

      // 3. Write each entry to the plugin assets dir via vault adapter.
      // Pre-create directories â€” adapter.mkdir is non-recursive on mobile.
      const dirsCreated = new Set();
      const ensureDir = async (relDir) => {
        if (!relDir || relDir === "." || dirsCreated.has(relDir)) return;
        if (await vio.exists(this, relDir)) { dirsCreated.add(relDir); return; }
        const parent = relDir.split("/").slice(0, -1).join("/");
        if (parent) await ensureDir(parent);
        await vio.mkdir(this, relDir);
        dirsCreated.add(relDir);
      };

      let written = 0;
      const total = fileNames.length;
      const progressEvery = Math.max(1, Math.floor(total / 20));
      for (const name of fileNames) {
        const targetRel = vio.join(this.pluginDirRel, "assets", name);
        const targetDir = targetRel.split("/").slice(0, -1).join("/");
        await ensureDir(targetDir);
        await vio.writeBinary(this, targetRel, entries[name].buffer.slice(
          entries[name].byteOffset,
          entries[name].byteOffset + entries[name].byteLength
        ));
        written++;
        if (written % progressEvery === 0) {
          notice.setMessage("Obsidi-Office: Installing " + written + " / " + total + " files...");
        }
      }

      notice.setMessage("Obsidi-Office: Assets installed (" + total + " files). Reload to activate.");
      setTimeout(() => notice.hide(), 6000);
      dlog("zip install complete:", total, "files");
      return true;
    } catch (err) {
      elog("zip install failed:", err);
      notice.setMessage("Obsidi-Office: Asset install failed: " + (err && err.message || err));
      setTimeout(() => notice.hide(), 10000);
      return false;
    }
  }

  // OnlyOffice DocumentServer generates themes.json + sdkjs/slide/themes/themes.js
  // at startup; the Docker image doesn't ship them. Without them the slide engine
  // 404s on every load and the Design/Layout pickers stay empty. Both files
  // satisfy their consumers when present-and-trivial: themes.json parser accepts
  // { "themes": [] }; slide themes.js loader's success callback fires on any 2xx
  // (even 0 bytes). Idempotent â€” re-runs on every load but no-ops once present.
  async _ensureThemesStubs() {
    try {
      const themesJsonRel = vio.join(this.onlyOfficeRel, "themes.json");
      if (!(await vio.exists(this, themesJsonRel))) {
        await vio.writeText(this, themesJsonRel, '{ "themes": [] }\n');
        dlog("wrote stub themes.json");
      }
      const slideThemesJsRel = vio.join(this.onlyOfficeRel, "sdkjs/slide/themes/themes.js");
      if (!(await vio.exists(this, slideThemesJsRel))) {
        await vio.writeText(this, slideThemesJsRel, "// Stub: DocumentServer-generated, intentionally empty in static bundle.\n");
        dlog("wrote stub sdkjs/slide/themes/themes.js");
      }
    } catch (err) {
      elog("ensureThemesStubs failed (non-fatal):", err);
    }
  }

  async _initTemplateDir() {
    const adapter = this.app.vault.adapter;
    // Docx template dir + Blank Document.docx
    const docxDir = this.settings.templateDir || "_docx-templates";
    if (!(await adapter.exists(docxDir))) {
      await adapter.mkdir(docxDir);
    }
    const blankDocxPath = docxDir + "/Blank Document.docx";
    if (!(await adapter.exists(blankDocxPath))) {
      const bytes = Uint8Array.from(atob(BLANK_DOCX_BASE64), (c) => c.charCodeAt(0));
      await adapter.writeBinary(blankDocxPath, bytes);
    }
    // Phase 8 — Pptx template dir + Blank Presentation.pptx
    const pptxDir = this.settings.pptxTemplateDir || "_pptx-templates";
    if (!(await adapter.exists(pptxDir))) {
      await adapter.mkdir(pptxDir);
    }
    const blankPptxPath = pptxDir + "/Blank Presentation.pptx";
    if (!(await adapter.exists(blankPptxPath))) {
      const bytes = Uint8Array.from(atob(BLANK_PPTX_BASE64), (c) => c.charCodeAt(0));
      await adapter.writeBinary(blankPptxPath, bytes);
    }
  }

  _injectTemplateDirCSS() {
    const styleId = "obsidi-office-hide-templates";
    let style = document.getElementById(styleId);
    if (!style) {
      style = document.createElement("style");
      style.id = styleId;
      document.head.appendChild(style);
    }
    // Phase 8 — hide both template dirs.
    const docxDir = this.settings.templateDir || "_docx-templates";
    const pptxDir = this.settings.pptxTemplateDir || "_pptx-templates";
    const hideDir = (d) =>
      '.nav-folder-title[data-path="' + d + '"], .nav-folder-title[data-path="' + d + '"] + .nav-folder-children { display: none !important; }';
    style.textContent = hideDir(docxDir) + " " + hideDir(pptxDir);
  }

  _printDocument(images, pageMmW, pageMmH) {
    // Direct print via hidden iframe in the parent (Obsidian) window.
    // Electron treats iframes as separate documents for print purposes:
    // iframe.contentWindow.print() prints ONLY the iframe content, not
    // the full BrowserWindow. Same pattern as P11_TaskBoard and
    // P13_HomeInventory.
    //
    // Pagination + exact layout: each image is OnlyOffice's authoritative
    // per-page render (asc_drawPrintPreview output). @page sized to the
    // document's actual page dimensions (mm) so 1 image = 1 print page,
    // and page-break-after: always enforces the page boundary.
    const pageSize = (pageMmW && pageMmH && pageMmW > 0 && pageMmH > 0)
      ? `${pageMmW}mm ${pageMmH}mm`
      : "letter";

    let body = "";
    for (const src of images) {
      body += '<img src="' + src + '">';
    }

    const html =
      '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Print</title><style>' +
      '@page { size: ' + pageSize + '; margin: 0; } ' +
      'html, body { margin: 0; padding: 0; background: white; } ' +
      'img { display: block; width: 100%; height: 100%; page-break-after: always; } ' +
      'img:last-child { page-break-after: avoid; } ' +
      '@media print { html, body { width: 100%; height: 100%; } }' +
      '</style></head><body>' + body + '</body></html>';

    const iframe = document.createElement("iframe");
    iframe.style.cssText =
      "position: fixed; left: -9999px; top: -9999px; width: 0; height: 0; " +
      "border: 0; visibility: hidden;";
    iframe.srcdoc = html;

    iframe.addEventListener("load", () => {
      // Small delay so the iframe's image elements have actually rendered
      // their bitmaps before the print dialog samples them.
      setTimeout(() => {
        try {
          const win = iframe.contentWindow;
          if (!win) return;
          win.focus();
          win.print();
        } catch (e) {
          elog("Print failed:", e);
          new obsidian.Notice("Print failed: " + (e.message || e));
        }
        // Detach the iframe shortly after â€” the print dialog has its own
        // captured render and stays open even if the iframe is removed.
        setTimeout(() => { try { iframe.remove(); } catch (e) {} }, 2000);
      }, 100);
    }, { once: true });

    document.body.appendChild(iframe);
    dlog("print: opened print dialog (" + images.length + " pages, " + pageSize + ")");
  }

  // Hybrid PDF export: each page = canvas image (visible) + invisible text
  // overlay (searchable). Text rendering mode 3 in PDF spec = "invisible";
  // viewers index it for Ctrl+F and copy-paste but don't paint it.
  //
  // payload: { docKey, pages: [{dataUrl, text, w, h}], basename }
  async _exportPdfToVault(payload) {
    // Note: no longer guarded on this.pluginAbs â€” Phase 10 baked pdf-lib
    // inline as PDFLIB_UMD_SOURCE, so loadPdfLib() needs no path. The old
    // guard returned silently on mobile (pluginAbs=null per Phase 14
    // hotfix) and left the iframe's "Generating PDF..." overlay stuck.
    dlog("_exportPdfToVault enter, pages:", payload.pages ? payload.pages.length : 0);
    const t0 = Date.now();
    let lib;
    try {
      lib = loadPdfLib();
      dlog("_exportPdfToVault loadPdfLib OK");
    } catch (err) {
      elog("_exportPdfToVault loadPdfLib threw:", err && err.stack || err);
      this._notifyPdfDone(null);
      throw err;
    }
    const { PDFDocument, StandardFonts, rgb } = lib;

    const pages = payload.pages || [];
    if (pages.length === 0) {
      new obsidian.Notice("PDF export: no pages");
      this._notifyPdfDone(null);  // hide overlay even on bail
      return;
    }

    dlog("Exporting PDF (" + pages.length + " pages)...");

    const pdfDoc = await PDFDocument.create();
    const helvetica = await pdfDoc.embedFont(StandardFonts.Helvetica);

    // mm â†’ PDF points: 1 inch = 25.4 mm = 72 points.
    const MM_TO_PT = 72 / 25.4;

    for (const p of pages) {
      const dataUrl = p.dataUrl || "";
      const b64 = dataUrl.indexOf(",") >= 0 ? dataUrl.slice(dataUrl.indexOf(",") + 1) : dataUrl;
      // Browser-safe base64 -> Uint8Array. Was Buffer.from(b64, "base64"),
      // but Capacitor WKWebView has no Node Buffer global -> "can't find
      // variable Buffer" on iPad. atob is universally available.
      const bin = atob(b64);
      const pngBytes = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) pngBytes[i] = bin.charCodeAt(i);
      const png = await pdfDoc.embedPng(pngBytes);

      // PDF page size: prefer the document's actual page dimensions in mm
      // (so the PDF is Letter/A4 sized, not viewport-canvas sized). Fall back
      // to the captured PNG dimensions if mm sizing isn't available.
      let pdfW, pdfH;
      if (p.pageMmW && p.pageMmH && p.pageMmW > 0 && p.pageMmH > 0) {
        pdfW = p.pageMmW * MM_TO_PT;
        pdfH = p.pageMmH * MM_TO_PT;
      } else {
        pdfW = png.width;
        pdfH = png.height;
      }

      const pdfPage = pdfDoc.addPage([pdfW, pdfH]);
      pdfPage.drawImage(png, { x: 0, y: 0, width: pdfW, height: pdfH });

      // Invisible text layer. opacity:0 + color rgb(1,1,1) keeps the bytes in
      // the page content stream (indexed by PDF readers for Ctrl+F and copy)
      // without painting. Helvetica is WinAnsi-only â€” we strip chars outside.
      //
      // Preferred path: spatially-aligned per-line placement using line-band
      // positions detected by pixel scan of the rendered canvas. Each text
      // chunk drawn at the detected baseline of its line, so search highlights
      // land on the correct visual line. Fallback: top-of-page text dump if
      // pixel-scan detection failed (e.g. tainted canvas).
      const runs = Array.isArray(p.textRuns) ? p.textRuns : [];
      const cw = p.w || png.width;
      const ch = p.h || png.height;
      const sx = pdfW / cw;
      const sy = pdfH / ch;

      if (runs.length > 0) {
        let placed = 0, skipped = 0;
        for (const r of runs) {
          const text = sanitizeForWinAnsi(r.text == null ? "" : String(r.text));
          if (!text.length) { skipped++; continue; }
          const fontSizePx = (typeof r.fontSizePx === "number" && r.fontSizePx > 0) ? r.fontSizePx : 12;
          const pdfFontSize = Math.max(1, fontSizePx * sy);
          const pdfX = r.x * sx;
          // Canvas y is from top, baseline; PDF y is from bottom, baseline.
          const pdfY = pdfH - r.y * sy;
          try {
            pdfPage.drawText(text, {
              x: pdfX,
              y: pdfY,
              font: helvetica,
              size: pdfFontSize,
              color: rgb(1, 1, 1),
              opacity: 0,
            });
            placed++;
          } catch (e) {
            skipped++;
          }
        }
        dlog("page " + (pages.indexOf(p) + 1) + ": placed " + placed + " runs, skipped " + skipped);
      } else {
        const text = sanitizeForWinAnsi(p.text || "");
        if (text.length > 0) {
          try {
            pdfPage.drawText(text, {
              x: 4,
              y: pdfH - 12,
              font: helvetica,
              size: 8,
              color: rgb(1, 1, 1),
              opacity: 0,
              maxWidth: pdfW - 8,
              lineHeight: 9,
            });
          } catch (e) {
            dlog("invisible text layer failed for one page (skipping):", e.message);
          }
        }
      }
      // Yield to the event loop between pages so the host-side notice/UI stays
      // responsive across the (~50-100ms per page) drawText operations.
      await new Promise((r) => setTimeout(r, 0));
    }

    const pdfBytes = await pdfDoc.save();

    // Resolve target path: <docDir>/<basename>.pdf next to the .docx.
    // Prefer docFilePath sent from the iframe; fall back to docKey lookup via bridge.
    // For transient print-via-PDF (Capacitor â€” window.print() is a no-op),
    // suffix with -print-<timestamp> so we can clean it up unambiguously and
    // avoid clobbering any user-generated PDF of the same basename.
    const isTransient = !!payload.transientPrint;
    const basename = (payload.basename || "document").replace(/\.(docx|pptx)$/i, "");
    const docPath = payload.docFilePath || this._lookupDocFilePath(payload.docKey) || "";
    const docDir = docPath ? docPath.split("/").slice(0, -1).join("/") : "";
    const targetBasename = isTransient ? (basename + "-print-" + Date.now()) : basename;
    const targetPath = (docDir ? docDir + "/" : "") + targetBasename + ".pdf";

    await this.app.vault.adapter.writeBinary(targetPath, pdfBytes);
    const ms = Date.now() - t0;
    dlog("PDF exported:", targetPath, "(" + (pdfBytes.byteLength / 1024).toFixed(1) + " KB) in", ms, "ms",
         isTransient ? "[transient print]" : "");

    // Open the produced PDF in a new Obsidian tab. Wait one tick for the
    // vault to register the new file before resolving its TFile.
    let openedLeaf = null;
    try {
      await new Promise((r) => setTimeout(r, 100));
      const file = this.app.vault.getAbstractFileByPath(targetPath);
      if (file instanceof obsidian.TFile) {
        openedLeaf = this.app.workspace.getLeaf("tab");
        await openedLeaf.openFile(file);
      } else {
        dlog("PDF written but TFile not yet resolvable for", targetPath);
      }
    } catch (err) {
      elog("Failed to open exported PDF:", err);
    }

    // Notify all editor iframes to hide their PDF loading overlay.
    this._notifyPdfDone(targetPath);

    if (isTransient) {
      // User has ~60s to invoke iOS share sheet â†’ AirPrint from the PDF
      // viewer. After the timeout, detach the leaf + delete the file so
      // the vault doesn't accumulate print-artifact PDFs.
      this._scheduleTransientPdfCleanup(targetPath, openedLeaf);
      new obsidian.Notice("Tap share â†’ Print to AirPrint. PDF auto-deletes in 60s.", 8000);
    } else {
      new obsidian.Notice("PDF exported");
    }
  }

  _scheduleTransientPdfCleanup(pdfPath, leaf) {
    const TIMEOUT_MS = 60 * 1000;
    setTimeout(async () => {
      try {
        // Detach the tab if still attached (no harm if user already closed it).
        if (leaf) {
          let stillAttached = false;
          this.app.workspace.iterateAllLeaves((l) => { if (l === leaf) stillAttached = true; });
          if (stillAttached) {
            try { leaf.detach(); } catch (e) {}
          }
        }
        const f = this.app.vault.getAbstractFileByPath(pdfPath);
        if (f && f instanceof obsidian.TFile) {
          await this.app.vault.delete(f);
          dlog("transient print PDF cleaned up:", pdfPath);
        } else {
          dlog("transient print PDF already gone:", pdfPath);
        }
      } catch (e) {
        elog("transient PDF cleanup failed:", e && e.message ? e.message : e);
      }
    }, TIMEOUT_MS);
  }

  // Re-render every open DocxView so a settings change that's only read at
  // editor-render time (e.g. params.enablePrint) takes effect without the
  // user having to manually close and reopen each tab. Calls the view's
  // onLoadFile with its current file â€” which clears containerEl and
  // rebuilds the iframe from scratch. Loses scroll position. Asks each
  // editor iframe to flush its save buffer first so 10 s auto-save
  // window edits aren't lost; waits a short grace period before reload.
  async _reloadOpenEditors() {
    const targets = [];
    this.app.workspace.iterateAllLeaves((leaf) => {
      // Phase 8 — reload both DocxView and PptxView leaves on settings change.
      if (leaf.view && leaf.view.file &&
          (leaf.view.getViewType() === VIEW_TYPE || leaf.view.getViewType() === VIEW_TYPE_PPTX)) {
        targets.push(leaf.view);
      }
    });
    if (targets.length === 0) return;
    dlog("reloading", targets.length, "open editor(s) after settings change");

    // Ask any open editor iframes to save first. mock-socket listens for
    // docx-viewer-save and runs triggerSaveToVault().
    try {
      const iframes = document.querySelectorAll("iframe");
      iframes.forEach((f) => {
        try { f.contentWindow.postMessage({ type: "docx-viewer-save" }, "*"); } catch (e) {}
      });
    } catch (e) {}
    // Give the save round-trip a moment (mock-socket save â†’ x2t â†’ vault
    // adapter writeBinary). 250 ms covers the desktop case; on mobile
    // the round-trip is similar (~140 ms observed on iPad).
    await new Promise((r) => setTimeout(r, 300));

    for (const view of targets) {
      try {
        // Trigger re-render. _onLoadFileInner clears the container and
        // rebuilds the editor with fresh params from current settings.
        view.onLoadFile(view.file).catch((err) => elog("editor reload failed:", err));
      } catch (e) {
        elog("editor reload threw:", e && e.message ? e.message : e);
      }
    }
  }

  _notifyPdfDone(targetPath) {
    try {
      const iframes = document.querySelectorAll("iframe");
      iframes.forEach((f) => {
        try { f.contentWindow.postMessage({ type: "docx-viewer-pdf-done", path: targetPath || null }, "*"); }
        catch (e) {}
      });
    } catch (e) {}
  }

  _lookupDocFilePath(docKey) {
    if (!this.bridge || !docKey) return null;
    const d = this.bridge.docs.get(docKey);
    return d ? d.filePath : null;
  }

  _injectSidecarCSS() {
    const styleId = "obsidi-office-hide-sidecars";
    let style = document.getElementById(styleId);
    if (!style) {
      style = document.createElement("style");
      style.id = styleId;
      document.head.appendChild(style);
    }
    // Hide *.docx.md and *.pptx.md files from file explorer (Phase 8 — both
    // sidecar variants indexed for graph/tags but shouldn't clutter the tree)
    style.textContent =
      '.nav-file-title[data-path$=".docx.md"], ' +
      '.nav-file-title[data-path$=".pptx.md"] { display: none !important; }';
  }

  async _openInView(file) {
    // Phase 8 — route by extension. .docx → DocxView, .pptx → PptxView.
    const viewType = (file && file.extension === "pptx") ? VIEW_TYPE_PPTX : VIEW_TYPE;
    const leaf = this.app.workspace.getLeaf(true);
    await leaf.setViewState({ type: viewType, active: true });
    const view = leaf.view;
    if (view && view.onLoadFile) await view.onLoadFile(file);
  }
}

// ===========================================================================
// MetadataModal â€” Obsidian tags + wikilinks for .docx sidecar
// ===========================================================================

class MetadataModal extends obsidian.Modal {
  constructor(app, docxPath) {
    super(app);
    this.docxPath = docxPath;
    this.sidecarPath = docxPath + ".md";
    this.tags = [];
    this.links = [];
  }

  async onOpen() {
    // Read existing sidecar
    await this._loadSidecar();

    const { contentEl } = this;
    contentEl.empty();
    contentEl.style.padding = "12px 16px";
    const titleRow = contentEl.createEl("div", { attr: { style: "display: flex; align-items: baseline; gap: 8px; margin-bottom: 8px;" } });
    titleRow.createEl("h3", { text: "Obsidian Metadata", attr: { style: "margin: 0;" } });
    titleRow.createEl("span", {
      text: this.docxPath.split("/").pop(),
      attr: { style: "color: var(--text-muted); font-size: 12px;" }
    });

    // --- Tags section ---
    contentEl.createEl("label", { text: "Tags", attr: { style: "font-weight: 600; font-size: 12px; display: block; margin: 4px 0 2px;" } });
    this._tagContainer = contentEl.createEl("div", { attr: { style: "display: flex; flex-wrap: wrap; gap: 3px; margin-bottom: 2px;" } });
    this._renderChips(this._tagContainer, this.tags, "tag");

    const tagInput = contentEl.createEl("input", { type: "text" });
    tagInput.style.cssText = "width: 100%; padding: 4px 8px; margin-bottom: 2px; font-size: 12px;";
    tagInput.placeholder = "Type to search tags...";

    const tagSuggest = contentEl.createEl("div", { attr: { style: "max-height: 100px; overflow-y: auto; border: 1px solid var(--background-modifier-border); border-radius: 4px; display: none; font-size: 12px;" } });

    tagInput.addEventListener("input", () => {
      const q = tagInput.value.replace(/^#/, "").toLowerCase();
      tagSuggest.empty();
      if (!q) { tagSuggest.style.display = "none"; return; }
      const allTags = Object.keys(this.app.metadataCache.getTags() || {})
        .map(t => t.replace(/^#/, ""))
        .filter(t => t.toLowerCase().includes(q) && !this.tags.includes(t))
        .slice(0, 10);
      if (allTags.length === 0) { tagSuggest.style.display = "none"; return; }
      tagSuggest.style.display = "block";
      for (const t of allTags) {
        const item = tagSuggest.createEl("div", { text: "#" + t, attr: { style: "padding: 4px 8px; cursor: pointer;" } });
        item.addEventListener("mouseenter", () => { item.style.background = "var(--background-modifier-hover)"; });
        item.addEventListener("mouseleave", () => { item.style.background = ""; });
        item.addEventListener("click", () => {
          this.tags.push(t);
          this._renderChips(this._tagContainer, this.tags, "tag");
          tagInput.value = "";
          tagSuggest.style.display = "none";
        });
      }
    });
    tagInput.addEventListener("keydown", (e) => {
      if (e.key === "Enter" && tagInput.value.trim()) {
        const t = tagInput.value.replace(/^#/, "").trim();
        if (t && !this.tags.includes(t)) {
          this.tags.push(t);
          this._renderChips(this._tagContainer, this.tags, "tag");
        }
        tagInput.value = "";
        tagSuggest.style.display = "none";
        e.preventDefault();
      }
    });

    // --- Links section ---
    contentEl.createEl("label", { text: "Links", attr: { style: "font-weight: 600; font-size: 12px; display: block; margin: 6px 0 2px;" } });
    this._linkContainer = contentEl.createEl("div", { attr: { style: "display: flex; flex-wrap: wrap; gap: 3px; margin-bottom: 2px;" } });
    this._renderChips(this._linkContainer, this.links, "link");

    const linkInput = contentEl.createEl("input", { type: "text" });
    linkInput.style.cssText = "width: 100%; padding: 4px 8px; margin-bottom: 2px; font-size: 12px;";
    linkInput.placeholder = "Type to search notes...";

    const linkSuggest = contentEl.createEl("div", { attr: { style: "max-height: 100px; overflow-y: auto; border: 1px solid var(--background-modifier-border); border-radius: 4px; display: none; font-size: 12px;" } });

    linkInput.addEventListener("input", () => {
      const q = linkInput.value.toLowerCase();
      linkSuggest.empty();
      if (!q) { linkSuggest.style.display = "none"; return; }
      const allNotes = this.app.vault.getMarkdownFiles()
        .filter(f => f.basename.toLowerCase().includes(q) &&
                     !f.path.endsWith(".docx.md") && !f.path.endsWith(".pptx.md"))
        .map(f => f.basename)
        .filter(n => !this.links.includes("[[" + n + "]]"))
        .slice(0, 10);
      if (allNotes.length === 0) { linkSuggest.style.display = "none"; return; }
      linkSuggest.style.display = "block";
      for (const n of allNotes) {
        const item = linkSuggest.createEl("div", { text: "[[" + n + "]]", attr: { style: "padding: 4px 8px; cursor: pointer;" } });
        item.addEventListener("mouseenter", () => { item.style.background = "var(--background-modifier-hover)"; });
        item.addEventListener("mouseleave", () => { item.style.background = ""; });
        item.addEventListener("click", () => {
          this.links.push("[[" + n + "]]");
          this._renderChips(this._linkContainer, this.links, "link");
          linkInput.value = "";
          linkSuggest.style.display = "none";
        });
      }
    });
    linkInput.addEventListener("keydown", (e) => {
      if (e.key === "Enter" && linkInput.value.trim()) {
        let n = linkInput.value.trim();
        if (!n.startsWith("[[")) n = "[[" + n + "]]";
        if (!this.links.includes(n)) {
          this.links.push(n);
          this._renderChips(this._linkContainer, this.links, "link");
        }
        linkInput.value = "";
        linkSuggest.style.display = "none";
        e.preventDefault();
      }
    });

    // --- Buttons ---
    const btnRow = contentEl.createEl("div", { attr: { style: "display: flex; gap: 8px; justify-content: flex-end; margin-top: 10px;" } });
    const cancelBtn = btnRow.createEl("button", { text: "Cancel" });
    cancelBtn.addEventListener("click", () => this.close());
    const saveBtn = btnRow.createEl("button", { text: "Save", cls: "mod-cta" });
    // Phase 8 — Phase 4 baseline #12 root cause: tag/link input only commits
    // to this.tags / this.links on Enter keypress. Clicking Save with text
    // still in the input field meant the tag was DROPPED — _saveSidecar saw
    // empty tags/links and silently took the "delete sidecar if empty" path
    // (no-op for a new file). The "fix" isn't an await; it's flushing
    // pending input before save.
    //
    // Timing note: keep close() synchronous (not after await) to match the
    // pre-Phase-8 ordering. Awaiting the vault write triggered an
    // "n.instanceOf is not a function" throw inside Obsidian's Modal.close()
    // — apparently an internal state issue that surfaces when vault events
    // fire between save and close. Fire-and-forget close avoids it; the
    // promise.catch wires error reporting back to the user via Notice.
    saveBtn.addEventListener("click", () => {
      // Commit pending tag input (user typed a tag but didn't press Enter)
      if (tagInput.value.trim()) {
        const t = tagInput.value.replace(/^#/, "").trim();
        if (t && !this.tags.includes(t)) {
          this.tags.push(t);
        }
        tagInput.value = "";
      }
      // Commit pending link input
      if (linkInput.value.trim()) {
        let n = linkInput.value.trim();
        if (!n.startsWith("[[")) n = "[[" + n + "]]";
        if (!this.links.includes(n)) {
          this.links.push(n);
        }
        linkInput.value = "";
      }
      // Fire-and-forget save; close immediately. Errors surface via Notice.
      const savePromise = this._saveSidecar();
      this.close();
      savePromise.catch((err) => {
        console.error("[obsidi-office] sidecar save failed:", err);
        new obsidian.Notice("Failed to save metadata: " + (err && err.message || err));
      });
    });
  }

  _renderChips(container, items, type) {
    container.empty();
    for (let i = 0; i < items.length; i++) {
      const chip = container.createEl("span", {
        text: type === "tag" ? "#" + items[i] : items[i],
        attr: { style: "display: inline-flex; align-items: center; gap: 3px; padding: 1px 6px; border-radius: 10px; font-size: 11px; background: var(--background-modifier-hover); border: 1px solid var(--background-modifier-border);" }
      });
      const x = chip.createEl("span", { text: "\u00D7", attr: { style: "cursor: pointer; font-size: 12px; line-height: 1; color: var(--text-muted);" } });
      const idx = i;
      x.addEventListener("click", () => {
        items.splice(idx, 1);
        this._renderChips(container, items, type);
      });
    }
  }

  async _loadSidecar() {
    const f = this.app.vault.getAbstractFileByPath(this.sidecarPath);
    if (!f || !(f instanceof obsidian.TFile)) return;
    const content = await this.app.vault.read(f);
    // Parse YAML frontmatter
    const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
    if (!fmMatch) return;
    // Phase 8 — ensure trailing newline so the per-tag/per-link regex
    // (`\s+-\s+.+\n`) matches the final list item. Without this, fmMatch[1]
    // captures `docx: ...\ntags:\n  - phase8` (no trailing \n — consumed by
    // the closing \n---), the repeat group matches zero times, and tags
    // silently disappear on reopen. Pre-existing bug discovered when fixing
    // Phase 4 baseline #12.
    const fm = fmMatch[1] + "\n";
    // Extract tags
    const tagsMatch = fm.match(/tags:\n((?:\s+-\s+.+\n)*)/);
    if (tagsMatch) {
      this.tags = tagsMatch[1].match(/^\s+-\s+(.+)$/gm)
        ?.map(l => l.replace(/^\s+-\s+/, "").trim()) || [];
    }
    // Extract links
    const linksMatch = fm.match(/links:\n((?:\s+-\s+.+\n)*)/);
    if (linksMatch) {
      this.links = linksMatch[1].match(/^\s+-\s+(.+)$/gm)
        ?.map(l => l.replace(/^\s+-\s+/, "").replace(/^["']|["']$/g, "").trim()) || [];
    }
  }

  async _saveSidecar() {
    const hasTags = this.tags.length > 0;
    const hasLinks = this.links.length > 0;

    if (!hasTags && !hasLinks) {
      // Delete sidecar if empty
      const f = this.app.vault.getAbstractFileByPath(this.sidecarPath);
      if (f && f instanceof obsidian.TFile) {
        await this.app.vault.delete(f);
        dlog("sidecar deleted (empty):", this.sidecarPath);
      }
      return;
    }

    const docxName = this.docxPath.split("/").pop();
    let yaml = "---\n";
    yaml += 'docx: "[[' + docxName + ']]"\n';
    if (hasTags) {
      yaml += "tags:\n";
      for (const t of this.tags) yaml += "  - " + t + "\n";
    }
    if (hasLinks) {
      yaml += "links:\n";
      for (const l of this.links) yaml += '  - "' + l + '"\n';
    }
    yaml += "---\n";

    const existing = this.app.vault.getAbstractFileByPath(this.sidecarPath);
    if (existing && existing instanceof obsidian.TFile) {
      await this.app.vault.modify(existing, yaml);
    } else {
      await this.app.vault.create(this.sidecarPath, yaml);
    }
    dlog("sidecar saved:", this.sidecarPath, "tags:", this.tags.length, "links:", this.links.length);
    new obsidian.Notice("Metadata saved for " + docxName);
  }

  onClose() { this.contentEl.empty(); }

  // Phase 8 — Obsidian's Modal.close() throws `n.instanceOf is not a function`
  // for MetadataModal instances (deep in minified app.js:1078854). The throw
  // is downstream of the visible close — the modal DOM is removed and
  // onClose runs — but the uncaught exception clutters the console and
  // could in theory break workspace state in some scenarios. Override here
  // to swallow the post-cleanup throw. Pre-existing issue, not introduced
  // by Phase 8.
  close() {
    try {
      super.close();
    } catch (err) {
      // Don't log — this fires reliably on every close and would spam.
      // The Modal is visually closed by this point.
    }
  }
}

// ===========================================================================
// FileNameModal â€” prompt for new document name
// ===========================================================================

class FileNameModal extends obsidian.Modal {
  constructor(app, defaultName, onSubmit, dotExt) {
    super(app);
    // Phase 8 — dotExt parameter ("." + extension, e.g. ".docx" or ".pptx").
    // Used to label the modal correctly; the actual filename suffix is applied
    // by the caller's onSubmit. Defaults to ".docx" if not passed (back-compat
    // with any caller that hasn't been updated).
    this.dotExt = (typeof dotExt === "string" && dotExt) ? dotExt : ".docx";
    const blanks = { ".docx": "Blank Document", ".pptx": "Blank Presentation" };
    const blankFor = blanks[this.dotExt] || "Blank Document";
    this.defaultName = defaultName === blankFor ? "" : defaultName;
    this.onSubmit = onSubmit;
  }
  onOpen() {
    const { contentEl } = this;
    const kind = this.dotExt === ".pptx" ? "Presentation" : "Document";
    contentEl.createEl("h3", { text: "New " + kind });
    contentEl.createEl("p", { text: "Enter a name for the new " + kind.toLowerCase() + ":" });
    const input = contentEl.createEl("input", { type: "text" });
    input.style.width = "100%";
    input.style.padding = "8px";
    input.style.marginBottom = "12px";
    input.placeholder = kind + " name";
    input.value = this.defaultName;
    input.focus();
    const btnRow = contentEl.createEl("div", { attr: { style: "display:flex;gap:8px;justify-content:flex-end;" } });
    const cancelBtn = btnRow.createEl("button", { text: "Cancel" });
    cancelBtn.addEventListener("click", () => this.close());
    const okBtn = btnRow.createEl("button", { text: "Create", cls: "mod-cta" });
    okBtn.addEventListener("click", () => {
      const name = input.value.trim();
      if (name) { this.onSubmit(name); this.close(); }
    });
    input.addEventListener("keydown", (e) => {
      if (e.key === "Enter") { const name = input.value.trim(); if (name) { this.onSubmit(name); this.close(); } }
      if (e.key === "Escape") this.close();
    });
  }
  onClose() { this.contentEl.empty(); }
}

module.exports = OnlyObsidianTestPlugin;
